import{_ as r,o as t,c as s,a2 as e}from"./chunks/framework.VxKNwi4m.js";const c=JSON.parse('{"title":"업무 관리 (Issues/Tasks)","description":"","frontmatter":{},"headers":[],"relativePath":"work-manage/issue.md","filePath":"work-manage/issue.md","lastUpdated":1783873990000}'),l={name:"work-manage/issue.md"};function o(i,a,n,h,u,d){return t(),s("div",null,[...a[0]||(a[0]=[e('<h1 id="업무-관리-issues-tasks" tabindex="-1">업무 관리 (Issues/Tasks) <a class="header-anchor" href="#업무-관리-issues-tasks" aria-label="Permalink to &quot;업무 관리 (Issues/Tasks)&quot;">​</a></h1><p>업무 관리 모듈은 프로젝트의 모든 작업 단위를 티켓(Ticket) 형태로 생성하고, 진행 상태 및 담당자를 추적하여 체계적으로 관리할 수 있는 핵심 도구입니다.</p><h2 id="_1-개요-및-접근-방법" tabindex="-1">1. 개요 및 접근 방법 <a class="header-anchor" href="#_1-개요-및-접근-방법" aria-label="Permalink to &quot;1. 개요 및 접근 방법&quot;">​</a></h2><p>업무 시스템은 사용자의 위치에 따라 두 가지 관점에서 접근할 수 있습니다.</p><ul><li><strong>전체 업무</strong>: 상단 메인 메뉴의 [업무]를 통해 접근합니다. 본인이 참여하고 있는 모든 프로젝트의 업무를 통합하여 조회할 수 있습니다.</li><li><strong>프로젝트 업무</strong>: 특정 프로젝트 내의 [업무] 메뉴를 통해 접근합니다. 해당 프로젝트에 속한 작업들만 집중적으로 관리할 때 사용합니다.</li></ul><h2 id="_2-업무-목록-및-필터링" tabindex="-1">2. 업무 목록 및 필터링 <a class="header-anchor" href="#_2-업무-목록-및-필터링" aria-label="Permalink to &quot;2. 업무 목록 및 필터링&quot;">​</a></h2><p>수많은 업무 중 필요한 정보를 효율적으로 찾기 위해 강력한 필터링 및 검색 기능을 제공합니다.</p><ul><li><strong>상태 필터</strong>: &#39;진행중(Open)&#39;인 업무만 보거나, &#39;종료(Closed)&#39;된 업무를 포함하여 모든 업무를 확인할 수 있습니다.</li><li><strong>다각화된 필터링</strong>: 업무 유형(Tracker), 우선순위, 담당자, 작성자, 목표 단계(Version) 등을 조합하여 목록을 좁힐 수 있습니다.</li><li><strong>검색</strong>: 제목이나 번호를 입력하여 특정 업무를 즉시 검색합니다.</li><li><strong>내 업무 보기</strong>: 본인이 담당자로 지정된 업무만 빠르게 필터링하여 일의 우선순위를 정할 수 있습니다.</li></ul><h2 id="_3-업무-작성-및-수정" tabindex="-1">3. 업무 작성 및 수정 <a class="header-anchor" href="#_3-업무-작성-및-수정" aria-label="Permalink to &quot;3. 업무 작성 및 수정&quot;">​</a></h2><p>업무를 생성할 때 상세한 정보를 입력하여 팀원 간의 혼선을 방지할 수 있습니다.</p><h3 id="핵심-정보-설정" tabindex="-1">핵심 정보 설정 <a class="header-anchor" href="#핵심-정보-설정" aria-label="Permalink to &quot;핵심 정보 설정&quot;">​</a></h3><ul><li><strong>업무 유형(Tracker)</strong>: 결함, 기능 개선, 지원 등 작업의 성격을 정의합니다.</li><li><strong>제목 및 설명</strong>: 작업 내용을 명확히 기술합니다. 설명 섹션은 **마크다운(Markdown)**을 지원하여 서식 있는 문서 작성이 가능합니다.</li><li><strong>우선순위</strong>: 낮음, 보통, 높음, 긴급 등으로 작업의 시급성을 표시합니다.</li><li><strong>진행 상태</strong>: 현재 업무의 흐름(Flow)에 맞는 상태를 선택합니다.</li></ul><h3 id="일정-및-담당자" tabindex="-1">일정 및 담당자 <a class="header-anchor" href="#일정-및-담당자" aria-label="Permalink to &quot;일정 및 담당자&quot;">​</a></h3><ul><li><strong>담당자</strong>: 해당 업무를 수행할 팀원을 지정합니다.</li><li><strong>시작 및 완료 기한</strong>: 작업의 예상 기간을 설정합니다. 기한이 지난 업무는 목록에서 붉은색으로 강조되어 주의를 환기합니다.</li><li><strong>진척도(%)</strong>: 업무 수행 완료율을 직접 입력하거나 하위 업무의 진행률을 바탕으로 자동 계산합니다.</li></ul><h3 id="공유자-watchers" tabindex="-1">공유자(Watchers) <a class="header-anchor" href="#공유자-watchers" aria-label="Permalink to &quot;공유자(Watchers)&quot;">​</a></h3><ul><li>직접적인 담당자는 아니지만, 해당 업무의 변경 사항을 실시간으로 알림 받아야 하는 팀원들을 추가할 수 있습니다.</li></ul><h2 id="_4-업무-상세-보기-및-협업" tabindex="-1">4. 업무 상세 보기 및 협업 <a class="header-anchor" href="#_4-업무-상세-보기-및-협업" aria-label="Permalink to &quot;4. 업무 상세 보기 및 협업&quot;">​</a></h2><p>업무 상세 페이지는 해당 작업과 관련된 모든 정보가 집약된 허브 역할을 합니다.</p><h3 id="협업-도구" tabindex="-1">협업 도구 <a class="header-anchor" href="#협업-도구" aria-label="Permalink to &quot;협업 도구&quot;">​</a></h3><ul><li><strong>댓글(의견) 작성</strong>: 진행 상황에 대해 팀원들과 소통할 수 있습니다. 마크다운과 파일 첨부를 지원합니다.</li><li><strong>파일 관리</strong>: 업무와 관련된 문서나 스크린샷 등을 업로드하고 관리합니다.</li><li><strong>실행 기록(History)</strong>: 업무의 상태 변화, 담당자 변경 등 모든 수정 이력을 타임라인 순으로 확인할 수 있습니다.</li></ul><h3 id="구조화된-업무-관리" tabindex="-1">구조화된 업무 관리 <a class="header-anchor" href="#구조화된-업무-관리" aria-label="Permalink to &quot;구조화된 업무 관리&quot;">​</a></h3><ul><li><strong>하위 업무(Sub-tasks)</strong>: 규모가 큰 작업을 여러 개의 작은 단위 업무로 쪼개어 관리할 수 있습니다.</li><li><strong>연결된 업무(Relations)</strong>: 업무 간의 선후 관계(Precedes/Follows), 중복 관계 등을 정의하여 작업 간의 연관성을 명시합니다.</li><li><strong>관련 회의</strong>: 해당 업무가 논의된 <strong>회의록</strong>이 있는 경우 자동으로 연결되어, 클릭 한 번으로 회의 맥락을 파악할 수 있습니다.</li></ul><h2 id="_5-업무-보고서-report" tabindex="-1">5. 업무 보고서 (Report) <a class="header-anchor" href="#_5-업무-보고서-report" aria-label="Permalink to &quot;5. 업무 보고서 (Report)&quot;">​</a></h2><p>프로젝트 내 [업무] -&gt; [보고서] 탭을 통해 전체적인 업무 통계를 확인할 수 있습니다.</p><ul><li>유형별, 상태별, 우선순위별 업무 분포를 차트와 표 형태로 제공하여 프로젝트의 건전성을 한눈에 파악합니다.</li><li>담당자별 업무 부하량을 체크하여 자원 배분을 최적화하는 데 도움을 줍니다.</li></ul>',25)])])}const _=r(l,[["render",o]]);export{c as __pageData,_ as default};
